import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  // Rule examples (simple → complex)
  it.todo("should return empty for empty grid");
  it.todo("should kill a single live cell (underpopulation, 0 neighbors)");
  it.todo("should kill two adjacent live cells (underpopulation, 1 neighbor each)");
  it.todo("should keep a live cell alive when it has 2 or 3 live neighbors (survival)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");

  // Pattern examples
  it.todo("should keep a block pattern unchanged (still life)");
  it.todo("should oscillate a vertical blinker into a horizontal blinker");
});

